```java
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

public class Main {
    // Token Bucket Rate Limiter
    private final int maxTokens;
    private final double refillRate;
    private final Map<String, double[]> buckets = new ConcurrentHashMap<>();

    public Main(int max, double rate) { this.maxTokens = max; this.refillRate = rate; }

    public boolean allow(String clientId) {
        double now = System.currentTimeMillis() / 1000.0;
        double[] b = buckets.computeIfAbsent(clientId, k -> new double[]{maxTokens, now});
        synchronized (b) {
            b[0] = Math.min(maxTokens, b[0] + (now - b[1]) * refillRate);
            b[1] = now;
            if (b[0] >= 1) { b[0]--; return true; }
            return false;
        }
    }

    public static void main(String[] args) {
        Main rl = new Main(5, 1.0);
        for (int i = 0; i < 8; i++)
            System.out.println("Req " + i + ": " + (rl.allow("user1") ? "OK" : "DENIED"));
    }
}
```

### Python Implementation

```python
import time
from collections import defaultdict

class TokenBucket:
    def __init__(self, max_tokens, refill_rate):
        self.max_tokens = max_tokens
        self.refill_rate = refill_rate
        self.buckets = defaultdict(lambda: [max_tokens, time.time()])

    def allow(self, client_id):
        b = self.buckets[client_id]
        now = time.time()
        b[0] = min(self.max_tokens, b[0] + (now - b[1]) * self.refill_rate)
        b[1] = now
        if b[0] >= 1: b[0] -= 1; return True
        return False

rl = TokenBucket(5, 1.0)
for i in range(8):
    print(f"Req {i}: {'OK' if rl.allow('user1') else 'DENIED'}")
```

